import { Nitro } from '@nitrots/nitro-renderer';
import { TargetHighlightOverlay } from './TargetHighlightOverlay';

let overlay: TargetHighlightOverlay | null = null;
let rafId = 0;
let started = false;

export const startTargetHighlightOverlay = (): void =>
{
if(started) return;
started = true;

overlay = new TargetHighlightOverlay();

const tick = () =>
{
try
{
const engine = Nitro.instance.roomEngine;
overlay?.update(engine);
}
catch { }

rafId = requestAnimationFrame(tick);
};

rafId = requestAnimationFrame(tick);

// optional cleanup if your client dispatches something on shutdown
window.addEventListener('nitro-dispose', () =>
{
if(rafId) cancelAnimationFrame(rafId);
rafId = 0;

overlay?.dispose();
overlay = null;

started = false;
});
};
